import unittest

from reading_list import Book, ReadingList


class ReadingListTests(unittest.TestCase):
    def setUp(self) -> None:
        self.books = [
            Book("Dune", "Frank Herbert", 1965),
            Book("Kindred", "Octavia Butler", 1979),
            Book("Parable of the Sower", "Octavia Butler", 1993),
        ]

    def test_books_are_kept_in_insertion_order(self) -> None:
        reading_list = ReadingList(self.books)
        self.assertEqual(reading_list.list_books(), self.books)

    def test_author_selection_is_exact(self) -> None:
        reading_list = ReadingList(self.books)
        self.assertEqual(
            reading_list.list_books(author="Octavia Butler"),
            self.books[1:],
        )

