from reading_list.formatting import format_books
from reading_list.models import Book


class FormattingTests(unittest.TestCase):
    def test_default_format(self) -> None:
        books = [Book("Dune", "Frank Herbert", 1965)]
        self.assertEqual(format_books(books), "Dune — Frank Herbert (1965)")

