        books = [
            Book("Dune", "Frank Herbert", 1965),
            Book("Kindred", "Octavia Butler", 1979),
        ]
        self.assertEqual(
            format_books(books, author="Octavia Butler"),
            "Kindred — Octavia Butler (1979)",
        )

